import { initializeApp } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-app.js"; import { getAuth, signInWithEmailAndPassword, createUserWithEmailAndPassword, signOut, onAuthStateChanged, sendPasswordResetEmail, updateProfile } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js"; const firebaseConfig = { apiKey: "AIzaSyCC8A3sa1uj1ffBZRng0riDpKCL4aNbatA", authDomain: "calculatorhub-b8ba8.firebaseapp.com", projectId: "calculatorhub-b8ba8", storageBucket: "calculatorhub-b8ba8.firebasestorage.app", messagingSenderId: "970415894424", appId: "1:970415894424:web:5f2aa0e8744a56f70445ed", measurementId: "G-7N9J6RMB4R" }; let app, auth; try { app = initializeApp(firebaseConfig); auth = getAuth(app); } catch (error) { console.error("Firebase initialization failed:", error); } document.addEventListener("DOMContentLoaded", () => { initAuthUI(); }); function initAuthUI() { const loginBtn = document.getElementById("nav-login-btn"); const logoutBtn = document.getElementById("nav-logout-btn"); const modalOverlay = document.getElementById("auth-modal"); const closeModalBtn = document.getElementById("auth-close"); const tabSignin = document.getElementById("tab-signin"); const tabSignup = document.getElementById("tab-signup"); const formSignin = document.getElementById("form-signin"); const formSignup = document.getElementById("form-signup"); const btnForgot = document.getElementById("btn-forgot"); const signinEmail = document.getElementById("signin-email"); const signinPass = document.getElementById("signin-pass"); const signupName = document.getElementById("signup-name"); const signupEmail = document.getElementById("signup-email"); const signupPass = document.getElementById("signup-pass"); const authAlert = document.getElementById("auth-alert"); const showAlert = (message, type = "error") => { if (!authAlert) return; authAlert.innerHTML = ` <div class="alert alert-${type === "error" ? "error" : "success"} animate-fade-in" style="padding: 0.75rem 1rem; font-size: 0.85rem; margin-bottom: 1rem;"> <span>${message}</span> </div> `; }; const clearAlert = () => { if (authAlert) authAlert.innerHTML = ""; }; if (loginBtn) { loginBtn.addEventListener("click", () => { clearAlert(); modalOverlay.classList.add("active"); }); } if (closeModalBtn) { closeModalBtn.addEventListener("click", () => { modalOverlay.classList.remove("active"); }); } if (modalOverlay) { modalOverlay.addEventListener("click", (e) => { if (e.target === modalOverlay) { modalOverlay.classList.remove("active"); } }); } if (tabSignin && tabSignup) { tabSignin.addEventListener("click", () => { clearAlert(); tabSignin.classList.add("active"); tabSignup.classList.remove("active"); formSignin.classList.add("active"); formSignup.classList.remove("active"); }); tabSignup.addEventListener("click", () => { clearAlert(); tabSignup.classList.add("active"); tabSignin.classList.remove("active"); formSignup.classList.add("active"); formSignin.classList.remove("active"); }); } if (formSignin) { formSignin.addEventListener("submit", async (e) => { e.preventDefault(); clearAlert(); const email = signinEmail.value.trim(); const pass = signinPass.value; try { await signInWithEmailAndPassword(auth, email, pass); modalOverlay.classList.remove("active"); signinEmail.value = ""; signinPass.value = ""; } catch (err) { showAlert(err.message.replace("Firebase: ", "")); } }); } if (formSignup) { formSignup.addEventListener("submit", async (e) => { e.preventDefault(); clearAlert(); const name = signupName.value.trim(); const email = signupEmail.value.trim(); const pass = signupPass.value; try { const userCredential = await createUserWithEmailAndPassword(auth, email, pass); await updateProfile(userCredential.user, { displayName: name }); updateAuthHeader(userCredential.user); modalOverlay.classList.remove("active"); signupName.value = ""; signupEmail.value = ""; signupPass.value = ""; } catch (err) { showAlert(err.message.replace("Firebase: ", "")); } }); } if (btnForgot) { btnForgot.addEventListener("click", async (e) => { e.preventDefault(); clearAlert(); const email = signinEmail.value.trim(); if (!email) { showAlert("Please enter your email address in the Sign In form first."); return; } try { await sendPasswordResetEmail(auth, email); showAlert("Password reset link has been sent to your email address.", "success"); } catch (err) { showAlert(err.message.replace("Firebase: ", "")); } }); } if (logoutBtn) { logoutBtn.addEventListener("click", async () => { try { await signOut(auth); } catch (err) { console.error("Sign out failed:", err); } }); } if (auth) { onAuthStateChanged(auth, (user) => { updateAuthHeader(user); }); } } function updateAuthHeader(user) { const loginBtn = document.getElementById("nav-login-btn"); const userProfile = document.getElementById("nav-user-profile"); const displayNameSpan = document.getElementById("user-display-name"); if (!loginBtn || !userProfile || !displayNameSpan) return; if (user) { loginBtn.style.display = "none"; userProfile.style.display = "flex"; const initial = (user.displayName || user.email || "?").charAt(0).toUpperCase(); displayNameSpan.innerHTML = ` <div class="nav-avatar" title="${user.displayName || user.email}">${initial}</div> <span style="font-weight: 500; font-size: 0.9rem; max-width: 120px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">${user.displayName || user.email.split('@')[0]}</span> `; } else { loginBtn.style.display = "inline-flex"; userProfile.style.display = "none"; displayNameSpan.innerHTML = ""; } }